import httpClient from "./httpClient";

export const customersApi = {
  getAll: async () => {
    const res = await httpClient.get("/customers");
    return res.data;
  },
  create: async (customer) => {
    const res = await httpClient.post("/customers", customer);
    return res.data;
  },
};
